"use client";

import Image from "next/image";
import { useState } from "react";
import { Ai43 } from "@/components/beste/piece/ai43";
import { Automation1 } from "@/components/beste/piece/automation1";
import { Automation2 } from "@/components/beste/piece/automation2";
import { Automation8 } from "@/components/beste/piece/automation8";
import { Automation10 } from "@/components/beste/piece/automation10";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";

type ComponentBackground =
  | { type: "dots" }
  | { type: "none" }
  | { type: "image"; src: string; alt?: string }
  | { type: "video"; src: string; alt?: string };

type FeatureMedia =
  | { type: "image"; src: string; alt?: string }
  | { type: "video"; src: string; alt?: string }
  | {
      type: "component";
      component: React.ReactNode;
      background?: ComponentBackground;
    };

interface FeatureItem {
  title: string;
  description: string;
  media: FeatureMedia;
}

interface Feature1Props {
  badge?: {
    label: string;
    variant?: "default" | "secondary" | "outline";
  };
  heading?: string;
  description?: string;
  features?: FeatureItem[];
  className?: string;
}

export const feature1Demo: Feature1Props = {
  badge: { label: "Automations", variant: "secondary" },
  heading: "Pick a capability, see the surface",
  description:
    "Open any row to expand its story. The right side updates with the live asset that ships with that capability.",
  features: [
    {
      title: "Wire up a single workflow node",
      description:
        "Drop a trigger or action node onto any canvas. Field labels and values come prebuilt, the app icon picks up your brand mark.",
      media: {
        type: "component",
        component: (
          <Automation2
            kind="action"
            app="Gmail"
            event="Send email"
            image="https://oud.pics/sm/l/gmail.jpeg"
            alt="Gmail"
            fields={[
              { label: "To", value: "{{customer.email}}" },
              { label: "Subject", value: "Your receipt is ready" },
              { label: "Template", value: "receipt-v3" },
            ]}
          />
        ),
      },
    },
    {
      title: "Trigger meets action, in one tile",
      description:
        "Show the full workflow at a glance. Two apps, two events, an arrow tells the story without an extra paragraph.",
      media: {
        type: "component",
        component: (
          <Automation1
            trigger={{
              src: "https://oud.pics/sm/l/stripe.jpeg",
              alt: "Stripe",
              event: "Payment received",
            }}
            action={{
              src: "https://oud.pics/sm/l/slack.svg",
              alt: "Slack",
              event: "Send #revenue alert",
            }}
          />
        ),
      },
    },
    {
      title: "Hand off the raw model output",
      description:
        "Download or copy the response as JSON. Useful in debug panels, eval reports, and tool-call documentation.",
      media: {
        type: "component",
        component: (
          <Ai43
            filename="response.json"
            content={`{
  "answer": "Use Redis INCR",
  "sources": 3,
  "latency_ms": 420
}`}
          />
        ),
      },
    },
    {
      title: "Toggle automations live",
      description:
        "An on/off card with run counts and a brand-aware tone. Drop it into dashboards so the team sees what's running without opening the editor.",
      media: {
        type: "component",
        component: (
          <Automation8
            name="Stripe → Slack revenue alerts"
            description="Posts a message in #revenue when a payment over $500 lands."
            image="https://oud.pics/sm/l/stripe.jpeg"
            alt="Stripe"
            active
            runsToday={28}
            tone="emerald"
          />
        ),
      },
    },
    {
      title: "Package recipes for installs",
      description:
        "Pre-built workflow recipes with a multi-app stack and an install count. Perfect for an integrations marketplace.",
      media: {
        type: "component",
        component: (
          <Automation10
            apps={[
              { image: "https://oud.pics/sm/l/stripe.jpeg", alt: "Stripe" },
              { image: "https://oud.pics/sm/l/notion.png", alt: "Notion" },
              { image: "https://oud.pics/sm/l/slack.svg", alt: "Slack" },
            ]}
            name="Sync paid invoices to Notion and ping Slack"
            description="Triggers on Stripe payment, logs the invoice in Notion, and posts a thread to #revenue."
            installs={4280}
            tone="primary"
          />
        ),
      },
    },
  ],
};

export function Feature1({
  badge,
  heading,
  description,
  features = [],
  className,
}: Feature1Props) {
  const [activeIndex, setActiveIndex] = useState(0);
  const activeMedia = features[activeIndex]?.media;

  return (
    <section className={cn("py-16 md:py-24", className)}>
      <div className="mx-auto max-w-6xl px-4 md:px-6">
        {(badge || heading || description) && (
          <div className="mx-auto mb-12 max-w-3xl text-center">
            {badge && (
              <div className="mb-4 flex justify-center">
                <Badge variant={badge.variant ?? "default"}>
                  {badge.label}
                </Badge>
              </div>
            )}
            {heading && (
              <h2 className="text-2xl font-semibold md:text-4xl">{heading}</h2>
            )}
            {description && (
              <p className="mt-4 text-base md:text-lg text-muted-foreground">
                {description}
              </p>
            )}
          </div>
        )}

        <div className="grid items-start gap-8 md:grid-cols-2 md:gap-12">
          <Accordion
            type="single"
            collapsible
            defaultValue="item-0"
            onValueChange={(value) => {
              if (!value) return;
              const next = Number(value.replace("item-", ""));
              if (!Number.isNaN(next)) setActiveIndex(next);
            }}
          >
            {features.map((feature, index) => (
              <AccordionItem key={index} value={`item-${index}`}>
                <AccordionTrigger className="text-left text-base font-medium md:text-lg">
                  {feature.title}
                </AccordionTrigger>
                <AccordionContent>
                  <p className="text-sm text-muted-foreground md:text-base">
                    {feature.description}
                  </p>
                  <div className="mt-4 md:hidden">
                    <FeatureMediaSurface media={feature.media} />
                  </div>
                </AccordionContent>
              </AccordionItem>
            ))}
          </Accordion>

          <div className="hidden md:block">
            {activeMedia && <FeatureMediaSurface media={activeMedia} />}
          </div>
        </div>
      </div>
    </section>
  );
}

function FeatureMediaSurface({ media }: { media: FeatureMedia }) {
  const componentBackground =
    media.type === "component" ? media.background ?? { type: "dots" } : null;
  const showDots = componentBackground?.type === "dots";

  return (
    <div
      className="relative flex aspect-[4/3] items-center justify-center overflow-hidden rounded-md border bg-muted/30"
      style={
        showDots
          ? {
              backgroundImage:
                "radial-gradient(circle, var(--border) 1px, transparent 1px)",
              backgroundSize: "16px 16px",
            }
          : undefined
      }
    >
      {componentBackground?.type === "image" && (
        <Image
          src={componentBackground.src}
          alt={componentBackground.alt ?? ""}
          fill
          className="object-cover"
          aria-hidden="true"
        />
      )}
      {componentBackground?.type === "video" && (
        <video
          src={componentBackground.src}
          autoPlay
          loop
          muted
          playsInline
          className="absolute inset-0 size-full object-cover"
        />
      )}

      {media.type === "video" ? (
        <video
          src={media.src}
          autoPlay
          loop
          muted
          playsInline
          aria-label={media.alt}
          className="size-full object-cover"
        />
      ) : media.type === "image" ? (
        <Image
          src={media.src}
          alt={media.alt ?? ""}
          fill
          className="object-cover"
        />
      ) : (
        <div className="relative flex size-full items-center justify-center">
          {media.component}
        </div>
      )}
    </div>
  );
}

"use client";

import { Braces, Copy } from "lucide-react";
import { cn } from "@/lib/utils";

interface Ai43Props {
  content?: string;
  filename?: string;
  className?: string;
}

export const ai43Demo: Ai43Props = {
  filename: "response.json",
  content: `{
  "answer": "Use Redis INCR",
  "sources": 3,
  "latency_ms": 420
}`,
};

export function Ai43({
  filename = "response.json",
  content = "{}",
  className,
}: Ai43Props) {
  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="flex w-full max-w-80 flex-col overflow-hidden rounded-md border border-border bg-card shadow-sm">
        <div className="flex items-center justify-between gap-2 border-b border-border px-3 py-1.5">
          <div className="flex items-center gap-1.5">
            <Braces
              className="size-3 text-muted-foreground"
              aria-hidden="true"
            />
            <span className="font-mono text-xs text-card-foreground">
              {filename}
            </span>
          </div>
          <button
            type="button"
            className="inline-flex items-center gap-1 rounded-sm px-1.5 py-0.5 text-xs text-muted-foreground hover:bg-muted hover:text-foreground"
            aria-label="Copy"
          >
            <Copy className="size-3" />
          </button>
        </div>
        <pre className="max-h-28 overflow-hidden whitespace-pre px-3 py-2 font-mono text-xs leading-relaxed text-card-foreground">
          {content}
        </pre>
      </div>
    </div>
  );
}

"use client";

import Image from "next/image";
import type { LucideIcon } from "lucide-react";
import {
  ArrowDown,
  Calendar,
  CreditCard,
  FileText,
  GitBranch,
  Hash,
  Mail,
  MessageSquare,
} from "lucide-react";
import { cn } from "@/lib/utils";

type AppPreset =
  | "slack"
  | "gmail"
  | "stripe"
  | "calendar"
  | "github"
  | "notion"
  | "discord";

interface Automation1Step {
  preset?: AppPreset;
  src?: string;
  alt?: string;
  event: string;
}

interface Automation1Props {
  trigger?: Automation1Step;
  action?: Automation1Step;
  triggerLabel?: string;
  actionLabel?: string;
  className?: string;
}

const APPS: Record<
  AppPreset,
  { label: string; icon: LucideIcon; tile: string }
> = {
  slack: { label: "Slack", icon: Hash, tile: "bg-violet-500 text-white" },
  gmail: { label: "Gmail", icon: Mail, tile: "bg-rose-500 text-white" },
  stripe: {
    label: "Stripe",
    icon: CreditCard,
    tile: "bg-indigo-500 text-white",
  },
  calendar: {
    label: "Calendar",
    icon: Calendar,
    tile: "bg-sky-500 text-white",
  },
  github: {
    label: "GitHub",
    icon: GitBranch,
    tile: "bg-neutral-900 text-white dark:bg-neutral-100 dark:text-neutral-900",
  },
  notion: {
    label: "Notion",
    icon: FileText,
    tile: "bg-neutral-900 text-white dark:bg-neutral-100 dark:text-neutral-900",
  },
  discord: {
    label: "Discord",
    icon: MessageSquare,
    tile: "bg-indigo-600 text-white",
  },
};

export const automation1Demo: Automation1Props = {
  triggerLabel: "When",
  actionLabel: "Then",
  trigger: {
    src: "https://oud.pics/sm/l/stripe.jpeg",
    alt: "Stripe",
    event: "Payment received",
  },
  action: {
    src: "https://oud.pics/sm/l/slack.svg",
    alt: "Slack",
    event: "Send #revenue alert",
  },
};

function Tile({ step }: { step: Automation1Step }) {
  if (step.src) {
    return (
      <span className="relative size-9 shrink-0 overflow-hidden rounded-md bg-muted">
        <Image
          src={step.src}
          alt={step.alt ?? ""}
          fill
          sizes="36px"
          className="object-cover"
        />
      </span>
    );
  }
  if (step.preset) {
    const cfg = APPS[step.preset];
    const Icon = cfg.icon;
    return (
      <span
        className={cn(
          "flex size-9 shrink-0 items-center justify-center rounded-md",
          cfg.tile
        )}
        aria-hidden="true"
      >
        <Icon className="size-4" />
      </span>
    );
  }
  return <span className="size-9 shrink-0 rounded-md bg-muted" aria-hidden="true" />;
}

function labelFor(step: Automation1Step) {
  if (step.alt) return step.alt;
  if (step.preset) return APPS[step.preset].label;
  return "App";
}

function Row({ kind, step }: { kind: string; step: Automation1Step }) {
  return (
    <div className="flex items-center gap-2 rounded-md border border-border p-2">
      <Tile step={step} />
      <div className="flex min-w-0 flex-1 flex-col">
        <div className="flex items-baseline gap-1.5">
          <span className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
            {kind}
          </span>
          <span className="truncate text-xs font-semibold text-card-foreground">
            {labelFor(step)}
          </span>
        </div>
        <span className="truncate text-xs text-muted-foreground">
          {step.event}
        </span>
      </div>
    </div>
  );
}

export function Automation1({
  trigger = { preset: "slack", event: "Trigger event" },
  action = { preset: "gmail", event: "Action event" },
  triggerLabel = "When",
  actionLabel = "Then",
  className,
}: Automation1Props) {
  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="flex w-full max-w-80 flex-col gap-1 rounded-md border border-border bg-card p-3 shadow-sm">
        <Row kind={triggerLabel} step={trigger} />
        <div className="flex items-center justify-center py-0.5">
          <span
            className="flex size-5 items-center justify-center rounded-full border border-border bg-muted"
            aria-hidden="true"
          >
            <ArrowDown className="size-3 text-muted-foreground" />
          </span>
        </div>
        <Row kind={actionLabel} step={action} />
      </div>
    </div>
  );
}

"use client";

import Image from "next/image";
import type { LucideIcon } from "lucide-react";
import {
  ArrowRight,
  CreditCard,
  FileText,
  Hash,
  Mail,
  MessageSquare,
  Plus,
} from "lucide-react";
import { cn } from "@/lib/utils";

type Tone =
  | "primary"
  | "foreground"
  | "violet"
  | "emerald"
  | "sky"
  | "amber";

type AppPreset = "slack" | "gmail" | "stripe" | "notion" | "discord";

interface AppItem {
  preset?: AppPreset;
  image?: string;
  alt?: string;
}

interface Automation10Props {
  apps?: AppItem[];
  name?: string;
  description?: string;
  installs?: number;
  installsLabel?: string;
  ctaLabel?: string;
  tone?: Tone;
  className?: string;
}

const PRESETS: Record<AppPreset, { icon: LucideIcon; tile: string }> = {
  slack: { icon: Hash, tile: "bg-violet-500 text-white" },
  gmail: { icon: Mail, tile: "bg-rose-500 text-white" },
  stripe: { icon: CreditCard, tile: "bg-indigo-500 text-white" },
  notion: {
    icon: FileText,
    tile: "bg-neutral-900 text-white dark:bg-neutral-100 dark:text-neutral-900",
  },
  discord: { icon: MessageSquare, tile: "bg-indigo-600 text-white" },
};

const ctaClasses: Record<Tone, string> = {
  primary: "bg-primary text-primary-foreground hover:bg-primary/90",
  foreground: "bg-foreground text-background hover:bg-foreground/90",
  violet: "bg-violet-500 text-white hover:bg-violet-600",
  emerald: "bg-emerald-500 text-white hover:bg-emerald-600",
  sky: "bg-sky-500 text-white hover:bg-sky-600",
  amber: "bg-amber-500 text-white hover:bg-amber-600",
};

export const automation10Demo: Automation10Props = {
  apps: [
    { image: "https://oud.pics/sm/l/stripe.jpeg", alt: "Stripe" },
    { image: "https://oud.pics/sm/l/notion.png", alt: "Notion" },
    { image: "https://oud.pics/sm/l/slack.svg", alt: "Slack" },
  ],
  name: "Sync paid invoices to Notion and ping Slack",
  description:
    "Triggers on Stripe payment, logs the invoice in Notion, and posts a thread to #revenue.",
  installs: 4280,
  installsLabel: "installs",
  ctaLabel: "Use recipe",
  tone: "primary",
};

function AppIcon({ item }: { item: AppItem }) {
  if (item.image) {
    return (
      <span className="relative size-7 shrink-0 overflow-hidden rounded-md bg-muted">
        <Image
          src={item.image}
          alt={item.alt ?? ""}
          fill
          sizes="28px"
          className="object-cover"
        />
      </span>
    );
  }
  if (item.preset) {
    const cfg = PRESETS[item.preset];
    const Icon = cfg.icon;
    return (
      <span
        className={cn(
          "flex size-7 shrink-0 items-center justify-center rounded-md",
          cfg.tile
        )}
        aria-hidden="true"
      >
        <Icon className="size-3.5" />
      </span>
    );
  }
  return (
    <span
      className="size-7 shrink-0 rounded-md bg-muted"
      aria-hidden="true"
    />
  );
}

export function Automation10({
  apps = [],
  name = "Recipe",
  description,
  installs,
  installsLabel = "installs",
  ctaLabel = "Use recipe",
  tone = "primary",
  className,
}: Automation10Props) {
  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="flex w-full max-w-80 flex-col gap-2 rounded-md border border-border bg-card p-3 shadow-sm">
        <div className="flex items-center gap-1">
          {apps.map((a, i) => (
            <div key={i} className="flex items-center gap-1">
              <AppIcon item={a} />
              {i < apps.length - 1 && (
                <ArrowRight
                  className="size-3 text-muted-foreground"
                  aria-hidden="true"
                />
              )}
            </div>
          ))}
        </div>
        <span className="text-sm font-semibold text-card-foreground">
          {name}
        </span>
        {description && (
          <p className="line-clamp-2 text-xs leading-snug text-muted-foreground">
            {description}
          </p>
        )}
        <div className="flex items-center justify-between border-t border-border pt-2">
          {typeof installs === "number" && (
            <span className="font-mono text-xs tabular-nums text-muted-foreground">
              {installs.toLocaleString()} {installsLabel}
            </span>
          )}
          <button
            type="button"
            className={cn(
              "ml-auto inline-flex items-center gap-1 rounded-sm px-2.5 py-1 text-xs font-semibold transition-colors",
              ctaClasses[tone]
            )}
          >
            <Plus className="size-3" aria-hidden="true" />
            {ctaLabel}
          </button>
        </div>
      </div>
    </div>
  );
}

"use client";

import Image from "next/image";
import { ChevronDown, Mail, MoreVertical } from "lucide-react";
import { cn } from "@/lib/utils";

interface Automation2Field {
  label: string;
  value: string;
}

interface Automation2Props {
  kind?: string;
  app?: string;
  event?: string;
  image?: string;
  alt?: string;
  fields?: Automation2Field[];
  configureLabel?: string;
  className?: string;
}

export const automation2Demo: Automation2Props = {
  kind: "Action",
  app: "Gmail",
  event: "Send email",
  image: "https://oud.pics/sm/l/gmail.jpeg",
  alt: "Gmail",
  configureLabel: "Configure",
  fields: [
    { label: "To", value: "{{customer.email}}" },
    { label: "Subject", value: "Your receipt is ready" },
    { label: "Template", value: "receipt-v3" },
  ],
};

export function Automation2({
  kind = "Step",
  app = "App",
  event = "Event",
  image,
  alt,
  fields = [],
  configureLabel = "Configure",
  className,
}: Automation2Props) {
  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="flex w-full max-w-80 flex-col overflow-hidden rounded-md border border-border bg-card shadow-sm">
        <div className="flex items-center gap-2 border-b border-border px-3 py-2">
          {image ? (
            <span className="relative size-7 shrink-0 overflow-hidden rounded-md bg-muted">
              <Image
                src={image}
                alt={alt ?? app}
                fill
                sizes="28px"
                className="object-cover"
              />
            </span>
          ) : (
            <span
              className="flex size-7 shrink-0 items-center justify-center rounded-md bg-muted-foreground text-background"
              aria-hidden="true"
            >
              <Mail className="size-3.5" />
            </span>
          )}
          <div className="flex min-w-0 flex-1 flex-col">
            <span className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
              {kind}
            </span>
            <span className="truncate text-sm font-semibold text-card-foreground">
              {app} · {event}
            </span>
          </div>
          <button
            type="button"
            className="text-muted-foreground hover:text-foreground"
            aria-label="More"
          >
            <MoreVertical className="size-4" />
          </button>
        </div>
        <div className="flex flex-col">
          {fields.map((f, i) => (
            <div
              key={i}
              className="flex items-center justify-between gap-2 border-t border-border px-3 py-1.5 first:border-t-0"
            >
              <span className="text-xs text-muted-foreground">{f.label}</span>
              <span className="truncate font-mono text-xs text-card-foreground">
                {f.value}
              </span>
            </div>
          ))}
          <div className="flex items-center justify-center gap-1 border-t border-border bg-muted/40 py-1.5 text-xs text-muted-foreground">
            <ChevronDown className="size-3" aria-hidden="true" />
            <span>{configureLabel}</span>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import Image from "next/image";
import { Zap } from "lucide-react";
import { cn } from "@/lib/utils";

type Tone =
  | "primary"
  | "foreground"
  | "violet"
  | "emerald"
  | "sky"
  | "amber";

interface Automation8Props {
  name?: string;
  description?: string;
  image?: string;
  alt?: string;
  active?: boolean;
  runsToday?: number;
  activeLabel?: string;
  pausedLabel?: string;
  runsLabel?: string;
  tone?: Tone;
  className?: string;
}

const switchOnClasses: Record<Tone, string> = {
  primary: "bg-primary",
  foreground: "bg-foreground",
  violet: "bg-violet-500",
  emerald: "bg-emerald-500",
  sky: "bg-sky-500",
  amber: "bg-amber-500",
};

const switchTextOn: Record<Tone, string> = {
  primary: "text-primary",
  foreground: "text-foreground",
  violet: "text-violet-600 dark:text-violet-400",
  emerald: "text-emerald-600 dark:text-emerald-400",
  sky: "text-sky-600 dark:text-sky-400",
  amber: "text-amber-600 dark:text-amber-400",
